fn create_backfill_blocking_handler<Types, Pool, Client>(
    pool: Pool,
    client: Client,
) -> Option<std::sync::Arc<dyn Fn(&reth_execution_types::Chain<Types::Primitives>) + Send + Sync>>
where
    Types: NodeTypes,
    Pool: reth_transaction_pool::TransactionPoolExt + Clone + 'static,
    Client: reth_provider::StateProviderFactory + reth_provider::BlockReaderIdExt + reth_provider::ChainSpecProvider + Clone + 'static,
{
    let handle = tokio::runtime::Handle::current();
    Some(std::sync::Arc::new(move |chain| {
        let tip = chain.tip();
        reth_transaction_pool::blocking_handlers::process_canonical_state_transactions(
            &client, &pool, tip, tip.number(), tip.hash(), &handle,
        );
    }))
}

